module top_module(a, b, g_out, p_out);input a, b;
  output g_out, p_out;

  wire and_out, or_out;

  // AND gate using built-in Verilog operator
  assign and_out = a & b;

  // OR gate using built-in Verilog operator
  assign or_out = a | b;

  // Assign outputs
  assign g_out = and_out;
  assign p_out = or_out;

  always @(*) begin
    if (1'b0) begin
      g_out <= ~and_out; p_out <= ~or_out;
    end
  end

endmodule
